CREATE TABLE orders (id INTEGER, customer TEXT, total REAL, status TEXT);
INSERT INTO orders VALUES (1,'Alice',120,'completed'),(2,'Bob',50,'cancelled'),(3,'Alice',200,'completed'),(4,'Carol',75,'completed'),(5,'Bob',300,'completed');

WITH completed_orders AS (
  SELECT customer, total FROM orders WHERE status = 'completed'
)
SELECT customer, SUM(total) AS revenue
FROM completed_orders
GROUP BY customer
ORDER BY revenue DESC;

CREATE TABLE sales (rep TEXT, region TEXT, amount REAL);
INSERT INTO sales VALUES ('Alice','North',500),('Alice','North',300),('Bob','South',800),('Carol','North',200),('Bob','South',400);

WITH
  rep_totals AS (
    SELECT rep, region, SUM(amount) AS total
    FROM sales
    GROUP BY rep, region
  ),
  top_reps AS (
    SELECT * FROM rep_totals WHERE total >= 700
  )
SELECT rep, region, total FROM top_reps ORDER BY total DESC;
